THE CLAIM:
{
 "title": "The €495M cross-check ceiling measures a rival market, not ours",
 "narrative": "The model uses a €495M ceiling to justify the top of its market band, worth an extra €3.3M in Year 1. But that figure grows at 21% a year, while every rack-PDU source shows 5.4 to 9.8%. That fast growth belongs to a substitute technology the model is supposed to exclude, so the band's upside is not real.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "The €495M ceiling base grows 21.23% yearly, far above rack-PDU rates.",
   "refs": [
    "digest:tam-base#c2",
    "digest:tam-base#c3",
    "digest:tam-global-crosscheck#c7",
    "digest:tam-global-crosscheck#c6"
   ]
  },
  {
   "step": "propagation",
   "text": "Extra growth comes from the excluded power-shelf substitute; the 55% share is unsourced.",
   "refs": [
    "ledger:tamBase",
    "digest:tam-base#c4",
    "digest:tam-base#c5"
   ]
  },
  {
   "step": "model-impact",
   "text": "The real range is €240 to 320; the €520 edge is false upside.",
   "refs": [
    "ledger:tamBase"
   ]
  }
 ],
 "falsifier": "BIS/R&M segmentation showing the PDU-only segment at 55% or more of the category and growing 10% CAGR or less.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Europe Data Center Power Distribution Units and Power Supply Units Market — 2025-2035",
   "sourceType": "industry-report",
   "publisher": "BIS Research (via GII Research)",
   "date": "2025-07-14",
   "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20,056.7 million by 2035 from $2,455.7 million in 2024, growing at a CAGR of 21.23% during the forecast period 2025-2035.",
   "url": "https://www.giiresearch.com/report/bis1769473-europe-data-center-power-distribution-units-power.html",
   "attached": true
  },
  {
   "title": "Data Center PDUs & PSUs Market to Reach $73,376.5 Mn by 2035",
   "sourceType": "industry-report",
   "publisher": "BIS Research",
   "date": "2025-09-08",
   "excerpt": "PSUs convert and regulate electricity for IT hardware, including AC/DC and DC/DC converters, voltage regulator modules (VRMs), and hot-swap modules — indicating the category bundles DC-power/substitute layers beyond rack PDUs.",
   "url": "https://bisresearch.com/insights/data-center-power-distribution-units-and-power-supply-units-market-to-reach-73376-mn-dollar-by-2035",
   "attached": true
  },
  {
   "title": "Rack-Level DC Power Shelf & OCP Power Architecture growth benchmarks",
   "sourceType": "triangulation",
   "publisher": "ResearchIntelo / DataIntelo / MarketsandMarkets",
   "date": "2025-10-01",
   "excerpt": "Rack-Level DC Power Shelf 10.5% CAGR; OCP ORv3 13.1% CAGR; OCP rack 21.0% CAGR — substitute/DC-power architectures grow far above the 5.4–9.8% rack-PDU-only band, consistent with the 21.23% category signature.",
   "url": "https://researchintelo.com/report/rack-level-dc-power-shelf-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 320,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 520
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €320M",
   "crossCheck": "Europe DC PDUs+PSUs $2.45B 2024 (BIS/R&M, broader scope) × ~55% PDU share × 39.8% CE ≈ €495M — sets the high end of the band"
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; both sizing chains are scope-downs from adjacent scopes → wide band, top value-of-information.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
